mapper.insert:

        	SELECT SEQ_IMPORT_ID.NEXTVAL FROM DUAL


        INSERT INTO IMPORT_MASTER (
             import_id
           , import_number
           , mem_id
           , status
           , importer_name
           , rep_name
           , tel_no
		   , email
		   , biz_reg_no
           , customs_id
           , address
           , overseas_biz_name 
           , overseas_country 
           , import_type
           , cargo_mgmt_no
           , trans_mode
           , vessel_name
           , vessel_nation 
           , arrival_est_date 
           , bonded_in_date 
           , origin_country 
           , arrival_port 
           , bl_no, awb_no 
           , submit_date
           , currency_code
           , pay_amount
           , invoice_no
           , invoice_date
           , contract_no
           , contract_date
           , po_no
           , po_date
           , total_weight 
           , origin_cert_yn
           , incoterms
           , freight_currency
           , freight_amt
           , insurance_currency
           , insurance_amt
