           , add_amt
           , total_tax_base 
           , total_duty
           , total_vat 
           , total_tax_sum
           , cont_no 
           , hs_code 
           , tax_type
           , tax_base_type
           , item_name_declared 
           , item_name_trade
           , model_name 
           , qty 
           , qty_unit 
           , unit_price 
           , total_amount 
           , net_weight
           , tax_base_amt_item
           , origin_code 
           , origin_mark_yn
           , officer_id
           , assign_date  
        ) VALUES (
             #{importId}
           , 'IMP-' || TO_CHAR(SYSDATE, 'YYYYMMDD') || '-' || LPAD(#{importId}, 6, '0')
           , #{memId} 
           , #{status} 
           , #{importerName}
           , #{repName} 
           , #{telNo}
           , #{email}
           , #{bizRegNo}
           , #{customsId} 
           , #{address}
           , #{overseasBizName} 
           , #{overseasCountry} 
           , #{importType}
           , #{cargoMgmtNo} 
           , #{transMode}
           , #{vesselName} 
           , #{vesselNation} 
           , #{arrivalEstDate}
           , #{bondedInDate} 
           , #{originCountry} 
           , #{arrivalPort} 
           , #{blNo} 
           , #{awbNo} 
           , SYSDATE
           , #{currencyCode} 
           , #{payAmount}
           , #{invoiceNo}
           , #{invoiceDate} 
           , #{contractNo}
           , #{contractDate} 
           , #{poNo}
           , #{poDate}
           , #{totalWeight} 
           , #{originCertYn} 
           , #{incoterms}
           , #{freightCurrency} 
           , #{freightAmt}
           , #{insuranceCurrency}
           , #{insuranceAmt}
           , #{addAmtCurrency} 
           , #{addAmt}
           , #{totalTaxBase}
           , #{totalDuty}
           , #{totalVat}
           , #{totalTaxSum} 
           , #{contNo}
           , #{hsCode}
           , #{taxType}
           , #{taxBaseType}
           , #{itemNameDeclared}
           , #{itemNameTrade} 
           , #{modelName}
           , #{qty}
           , #{qtyUnit}
           , #{unitPrice}
           , #{totalAmount}
           , #{netWeight}
           , #{taxBaseAmtItem}
           , #{originCode}
           , #{originMarkYn}
           , #{officerId}
           , #{assignDate}
        )

mapper.select:
SELECT IMPORT_ID 
FROM IMPORT_MASTER 
WHERE IMPORT_NUMBER = #{importNumber}

SELECT STATUS AS "status", COUNT(*) AS "count" FROM IMPORT_MASTER
AND OFFICER_ID = #{memId}
AND 1=1
AND MEM_ID = #{memId}
GROUP BY STATUS
